description:
Implement the .raw accessor on JinjaPromptValue - returns untyped Jinja value bypassing typed traversal and budgets.

Location: crates/baml-bridge/src/prompt/jinja.rs

```rust
impl JinjaPromptValue {
    /// Return raw untyped value bypassing typed traversal and budgets
    fn raw_value(&self) -> Value {
        baml_value_to_jinja(&self.pv.value)
    }
}

/// Convert BamlValue to plain Jinja Value (no typed wrapper)
fn baml_value_to_jinja(value: &BamlValue) -> Value {
    match value {
        BamlValue::String(s) => Value::from(s.as_str()),
        BamlValue::Int(i) => Value::from(*i),
        BamlValue::Float(f) => Value::from(*f),
        BamlValue::Bool(b) => Value::from(*b),
        BamlValue::Null => Value::from(()),  // minijinja none
        BamlValue::List(items) => {
            Value::from_iter(items.iter().map(baml_value_to_jinja))
        }
        BamlValue::Map(map) => {
            Value::from_iter(
                map.iter().map(|(k, v)| (k.clone(), baml_value_to_jinja(v)))
            )
        }
        BamlValue::Class(name, fields) => {
            // Treat as map with string keys
            Value::from_iter(
                fields.iter().map(|(k, v)| (k.clone(), baml_value_to_jinja(v)))
            )
        }
        BamlValue::Enum(_, variant) => Value::from(variant.as_str()),
        BamlValue::Media(m) => {
            // Serialize to JSON-like structure
            let mut map = std::collections::BTreeMap::new();
            map.insert('type', Value::from(m.media_type.to_string()));
            // ... other media fields
            Value::from_iter(map)
        }
    }
}
```

Key behavior:
- .raw bypasses typed traversal
- .raw bypasses budget caps
- .raw['field'] for accessing shadowed reserved names
- Null becomes minijinja none (Value::from(())) so {% if raw is none %} works
